// Conditional Loading Wrapper
export const LoadingWrapper = ({
  loading = false,
  type = 'classic',
  text,
  fallback,
  children,
  ...props
}) => {
  if (loading) {
    return fallback || <Loading type={type} text={text} layout="inline" {...props} />;
  }
  
  return children;
};

export default Loading;
